# 025-quasi_geo-runner.R
# Generated by behavior-preserving split of quasi_geo_test.R.

qgt_add_overlap_diagnostics <- function(estimates) {
  if (is.null(estimates) || !nrow(estimates)) return(estimates)
  out <- copy(estimates)
  out[, `:=`(
    overlap_event_n = 0L,
    same_geo_overlap_event_n = 0L,
    overlap_contamination_score = 0
  )]
  for (i in seq_len(nrow(out))) {
    overlaps <- out$event_id != out$event_id[i] &
      out$event_start <= out$event_end[i] &
      out$event_end >= out$event_start[i]
    same_geo <- overlaps & out$geo == out$geo[i]
    out$overlap_event_n[i] <- sum(overlaps, na.rm = TRUE)
    out$same_geo_overlap_event_n[i] <- sum(same_geo, na.rm = TRUE)
    out$overlap_contamination_score[i] <- qgt_clip(0.10 * out$overlap_event_n[i] + 0.20 * out$same_geo_overlap_event_n[i], 0, 1)
  }
  out[overlap_event_n > 0 & !grepl("overlapping_events", diagnostic_reason, fixed = TRUE),
      diagnostic_reason := paste(diagnostic_reason, "overlapping_events", sep = "|")]
  out[]
}
run_quasi_geo_test <- function(input_data,
                               date_col,
                               dep_var_col,
                               geo_col,
                               holdout_col = NULL,
                               holdout_value = TRUE,
                               holdout_last_n = 0L,
                               variable_map = NULL,
                               media_cols = character(),
                               control_cols = character(),
                               normalize = c("geo_mean_index", "none"),
                               pre_weeks = 8L,
                               post_weeks = 4L,
                               rolling_window = 8L,
                               min_abs_change = 0,
                               min_pct_change = 0.25,
                               min_robust_z = 1.5,
                               min_volume = 1e-8,
                               media_cutoff_pct = 0.10,
                               donor_contamination_pct = 0.20,
                               other_media_contamination_pct = 0.25,
                               min_donors = 3L,
                               mde_alpha = 0.05,
                               mde_power = 0.80,
                               lambda_grid = 10 ^ seq(-4, 2, length.out = 20),
                               min_evidence_tier_to_keep = NULL,
                               min_evidence_score_to_keep = NULL,
                               min_evidence_score_for_prior = NULL,
                               min_evidence_score_for_calibration = NULL,
                               period_days = 7L,
                               output_dir = NULL,
                               prefix = "quasi_geo") {
  normalize <- match.arg(normalize)
  known_tiers <- c("not_estimable", "weak_noisy_estimate", "moderate_quasi_geo", "strong_quasi_geo")
  if (!is.null(min_evidence_tier_to_keep) && nzchar(as.character(min_evidence_tier_to_keep)[1]) &&
      !as.character(min_evidence_tier_to_keep)[1] %in% known_tiers) {
    stop("Unknown min_evidence_tier_to_keep: ", as.character(min_evidence_tier_to_keep)[1],
         ". Expected one of: ", paste(known_tiers, collapse = ", "))
  }
  dt <- as.data.table(copy(input_data))
  vm <- qgt_parse_variable_map(variable_map, media_cols)
  for (i in seq_len(nrow(vm))) {
    if (is.na(vm$modeled_x_col[i]) || !nzchar(trimws(vm$modeled_x_col[i])) || !vm$modeled_x_col[i] %in% names(dt)) {
      if (vm$variable[i] %in% names(dt)) {
        vm$modeled_x_col[i] <- vm$variable[i]
      } else {
        stop("variable_map row for variable '", vm$variable[i], "' has unrecoverable modeled_x_col. ",
             "Provide modeled_x_col or include a data column named '", vm$variable[i], "'.")
      }
    }
    if (is.na(vm$spend_col[i]) || !nzchar(trimws(vm$spend_col[i]))) vm$spend_col[i] <- vm$modeled_x_col[i]
  }
  req <- unique(c(date_col, dep_var_col, geo_col, holdout_col, vm$modeled_x_col, vm$spend_col, control_cols))
  miss <- setdiff(req, names(dt))
  if (length(miss)) stop("Missing input columns: ", paste(miss, collapse = ", "))
  dt[, (date_col) := qgt_date(get(date_col))]
  data.table::setorderv(dt, c(geo_col, date_col))
  dt[, (dep_var_col) := qgt_num(get(dep_var_col))]
  raw_dep_col <- "..qgt_raw_dep"
  while (raw_dep_col %in% names(dt)) raw_dep_col <- paste0(raw_dep_col, "_")
  dt[, (raw_dep_col) := qgt_num(get(dep_var_col))]
  for (cc in unique(c(vm$modeled_x_col, vm$spend_col, control_cols))) dt[, (cc) := qgt_num(get(cc))]
  holdout_info <- qgt_apply_holdout_flag(
    dt = dt,
    date_col = date_col,
    holdout_col = holdout_col,
    holdout_value = holdout_value,
    holdout_last_n = holdout_last_n
  )
  dt <- holdout_info$data
  holdout_audit <- holdout_info$audit
  vm <- qgt_assign_raw_media_cols(dt, vm)
  vm <- qgt_assign_raw_spend_cols(dt, vm)
  rollup_lookup <- qgt_rollup_lookup(vm)
  if (normalize == "geo_mean_index") {
    dt <- qgt_mean_index_by_geo(dt, unique(c(dep_var_col, vm$modeled_x_col)), geo_col, train_col = "is_qgt_training__")
  }
  dt_estimation <- dt[is_qgt_training__ == TRUE]
  events <- rbindlist(lapply(seq_len(nrow(vm)), function(i) {
    qgt_event_scan_one(
      dt = dt_estimation,
      date_col = date_col,
      geo_col = geo_col,
      variable = vm$variable[i],
      media_col = vm$modeled_x_col[i],
      pre_weeks = pre_weeks,
      post_weeks = post_weeks,
      min_abs_change = min_abs_change,
      min_pct_change = min_pct_change,
      min_robust_z = min_robust_z,
      min_volume = min_volume,
      media_cutoff_pct = media_cutoff_pct,
      rolling_window = rolling_window,
      period_days = period_days
    )
  }), use.names = TRUE, fill = TRUE)
  if (is.null(events) || !nrow(events)) events <- qgt_empty_candidate_events()
  if (nrow(events)) {
    data.table::setorder(events, variable, geo, event_start)
    events <- events[, .SD[1], by = .(variable, geo, event_start)]
  }
  events <- qgt_attach_rollup_metadata(events, rollup_lookup)
  estimates <- if (nrow(events)) rbindlist(lapply(seq_len(nrow(events)), function(ii) {
    ev <- events[ii]
    media_col <- vm[variable == ev$variable[1], modeled_x_col[1]]
    spend_col <- vm[variable == ev$variable[1], raw_spend_col__[1]]
    qgt_estimate_event(
      dt = dt_estimation,
      event = ev,
      date_col = date_col,
      dep_var_col = dep_var_col,
      raw_dep_col = raw_dep_col,
      geo_col = geo_col,
      media_col = media_col,
      raw_media_col = vm[variable == ev$variable[1], raw_media_col__[1]],
      spend_col = spend_col,
      all_media_cols = vm$modeled_x_col,
      all_raw_media_cols = stats::setNames(vm$raw_media_col__, vm$modeled_x_col),
      all_spend_cols = stats::setNames(vm$raw_spend_col__, vm$modeled_x_col),
      control_cols = control_cols,
      pre_weeks = pre_weeks,
      post_weeks = post_weeks,
      min_volume = min_volume,
      donor_contamination_pct = donor_contamination_pct,
      other_media_contamination_pct = other_media_contamination_pct,
      min_donors = min_donors,
      mde_alpha = mde_alpha,
      mde_power = mde_power,
      lambda_grid = lambda_grid
    )
  }), use.names = TRUE, fill = TRUE) else qgt_empty_event_estimates()
  estimates <- qgt_add_overlap_diagnostics(estimates)
  estimates <- qgt_classify_evidence_events(estimates)
  national_diagnostics <- qgt_national_repeated_media_diagnostics(dt_estimation, date_col, geo_col, vm)
  event_estimates_all <- rbindlist(list(estimates, national_diagnostics), use.names = TRUE, fill = TRUE)
  event_estimates_all <- qgt_classify_evidence_events(event_estimates_all)
  event_estimates_all <- qgt_attach_rollup_metadata(event_estimates_all, rollup_lookup)
  estimates <- qgt_attach_rollup_metadata(estimates, rollup_lookup)
  prior_events <- copy(event_estimates_all)
  if (!is.null(min_evidence_score_for_prior)) {
    prior_keep <- qgt_num(min_evidence_score_for_prior)[1]
    if (is.finite(prior_keep)) prior_events <- prior_events[evidence_score >= prior_keep]
  }
  calibration_events_all <- copy(event_estimates_all)
  if (!is.null(min_evidence_score_for_calibration)) {
    cal_keep <- qgt_num(min_evidence_score_for_calibration)[1]
    if (is.finite(cal_keep)) calibration_events_all <- calibration_events_all[evidence_score >= cal_keep]
  }
  if (!is.null(min_evidence_tier_to_keep) && nzchar(as.character(min_evidence_tier_to_keep)[1]) && nrow(estimates)) {
    keep_rank <- qgt_evidence_rank(as.character(min_evidence_tier_to_keep)[1])
    estimates <- estimates[qgt_evidence_rank(evidence_tier) >= keep_rank]
  }
  if (!is.null(min_evidence_score_to_keep) && nrow(estimates)) {
    score_keep <- qgt_num(min_evidence_score_to_keep)[1]
    if (is.finite(score_keep)) estimates <- estimates[evidence_score >= score_keep]
  }
  summary_all <- qgt_summarize_dose_response(event_estimates_all)
  summary <- qgt_summarize_dose_response(estimates)
  prior_recommendations <- qgt_build_prior_recommendations(prior_events)
  bundle_prior_recommendations <- qgt_build_bundle_prior_recommendations(prior_events)
  evidence_summary <- qgt_build_evidence_summary(event_estimates_all, "overall")
  variable_evidence_summary <- qgt_build_evidence_summary(event_estimates_all, "variable")
  estimand_evidence_summary <- qgt_build_evidence_summary(event_estimates_all, "estimand")
  rollup_evidence_summary <- qgt_build_rollup_evidence_summary(event_estimates_all)
  summary_all <- qgt_attach_rollup_metadata(summary_all, rollup_lookup)
  summary <- qgt_attach_rollup_metadata(summary, rollup_lookup)
  prior_recommendations <- qgt_attach_rollup_metadata(prior_recommendations, rollup_lookup)
  variable_evidence_summary <- qgt_attach_rollup_metadata(variable_evidence_summary, rollup_lookup)
  calibration_events <- calibration_events_all[recommended_use == "calibration"]
  directional_prior_events <- event_estimates_all[recommended_use == "directional_prior"]
  diagnostic_events <- event_estimates_all[recommended_use == "diagnostic_only"]
  if (!is.null(output_dir) && nzchar(output_dir)) {
    dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
    fwrite(events, file.path(output_dir, paste0(prefix, "_candidate_events.csv")))
    fwrite(event_estimates_all, file.path(output_dir, paste0(prefix, "_event_estimates_all.csv")))
    fwrite(estimates, file.path(output_dir, paste0(prefix, "_event_estimates.csv")))
    fwrite(calibration_events, file.path(output_dir, paste0(prefix, "_calibration_events.csv")))
    fwrite(directional_prior_events, file.path(output_dir, paste0(prefix, "_directional_prior_events.csv")))
    fwrite(diagnostic_events, file.path(output_dir, paste0(prefix, "_diagnostic_events.csv")))
    fwrite(summary_all, file.path(output_dir, paste0(prefix, "_dose_response_summary_all.csv")))
    fwrite(summary, file.path(output_dir, paste0(prefix, "_dose_response_summary.csv")))
    fwrite(prior_recommendations, file.path(output_dir, paste0(prefix, "_prior_recommendations.csv")))
    fwrite(bundle_prior_recommendations, file.path(output_dir, paste0(prefix, "_bundle_prior_recommendations.csv")))
    fwrite(evidence_summary, file.path(output_dir, paste0(prefix, "_evidence_summary.csv")))
    fwrite(variable_evidence_summary, file.path(output_dir, paste0(prefix, "_variable_evidence_summary.csv")))
    fwrite(estimand_evidence_summary, file.path(output_dir, paste0(prefix, "_estimand_evidence_summary.csv")))
    fwrite(rollup_evidence_summary, file.path(output_dir, paste0(prefix, "_rollup_evidence_summary.csv")))
  }
  normalized_data <- copy(dt)
  raw_media_cols <- intersect(vm$raw_media_col__, names(normalized_data))
  if (length(raw_media_cols)) normalized_data[, (raw_media_cols) := NULL]
  raw_spend_cols <- intersect(vm$raw_spend_col__, names(normalized_data))
  if (length(raw_spend_cols)) normalized_data[, (raw_spend_cols) := NULL]
  if ("is_qgt_training__" %in% names(normalized_data)) normalized_data[, is_qgt_training__ := NULL]
  if (raw_dep_col %in% names(normalized_data)) normalized_data[, (raw_dep_col) := NULL]
  list(
    candidate_events = events[],
    event_estimates_all = event_estimates_all[],
    event_estimates = estimates[],
    calibration_events = calibration_events[],
    directional_prior_events = directional_prior_events[],
    diagnostic_events = diagnostic_events[],
    dose_response_summary_all = summary_all[],
    dose_response_summary = summary[],
    prior_recommendations = prior_recommendations[],
    bundle_prior_recommendations = bundle_prior_recommendations[],
    evidence_summary = evidence_summary[],
    variable_evidence_summary = variable_evidence_summary[],
    estimand_evidence_summary = estimand_evidence_summary[],
    rollup_evidence_summary = rollup_evidence_summary[],
    holdout_audit = holdout_audit,
    normalized_data = normalized_data[],
    notes = c(
      "Designed to detect natural or unannounced geo tests.",
      "Event detection is signed: up ramps, down ramps, mixed ramps, and media cutoffs are retained.",
      "No default hard qualification is applied; events are estimated when possible and diagnosed afterward with numeric evidence_score.",
      "False-positive review includes pre-period placebo, donor-geo placebo, and leave-one-donor-out sensitivity diagnostics.",
      "evidence_score_0_100 is an analyst-facing ranking/filter built from GeoLift/matched-market-style diagnostics, not statistical proof.",
      "Use min_evidence_score_to_keep or min_evidence_tier_to_keep only for optional reporting/sensitivity filtering; prior generation uses min_evidence_score_for_prior.",
      "normalize = 'geo_mean_index' is the fallback when population or comparable exposure denominators are unavailable."
    )
  )
}
